import sys

def main():
    data = sys.stdin.read().splitlines()
    n, m = map(int, data[0].split())
    grid = data[1:1+n]
    q = int(data[1+n])
    queries = [tuple(map(int, line.split())) for line in data[2+n:2+n+q]]
    # precompute conflict columns (see editorial)
    conflict = [0]*m
    for i in range(1, n):
        for j in range(1, m):
            if grid[i][j-1] == 'X' and grid[i-1][j] == 'X':
                conflict[j] = 1
    pref = [0]*(m+1)
    for j in range(1, m+1):
        pref[j] = pref[j-1] + conflict[j-1]
    out = []
    for l, r in queries:
        if pref[r-1] - pref[l-1] == 0:
            out.append('YES')
        else:
            out.append('NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()
```

